const items = $input.all();
const now = new Date();
now.setHours(0,0,0,0);

const actions = [];

for (const item of items) {
  const row = item.json;
  if (!row.Email || row.Status === 'Cancelled') continue;

  const base = {
    name: row.Name || 'Member',
    email: row.Email,
    phone: row.Phone || '',
    next_class_date: row.Next_Class_Date || '',
    next_class_time: row.Next_Class_Time || '',
    next_class_name: row.Next_Class_Name || 'your class',
    last_visit_date: row.Last_Visit_Date || '',
    membership_type: row.Membership_Type || 'Standard',
    classes_this_month: parseInt(row.Classes_This_Month || '0'),
    reminder_sent: row.Reminder_Sent || '',
    churn_email_sent: row.Churn_Email_Sent || '',
    status: row.Status || 'Active'
  };

  // Class reminder: has a class today and reminder not yet sent
  if (base.next_class_date) {
    let classDate;
    try {
      classDate = new Date(base.next_class_date);
      classDate.setHours(0,0,0,0);
    } catch { classDate = null; }

    if (classDate) {
      const daysUntilClass = Math.round((classDate - now) / (1000 * 60 * 60 * 24));
      if (daysUntilClass === 1 && base.reminder_sent !== 'Yes') {
        actions.push({ json: { ...base, _action: 'class_reminder' } });
      }
    }
  }

  // Churn detection: hasn't visited in 14+ days, is active, no churn email sent
  if (base.last_visit_date && base.status === 'Active') {
    let lastVisit;
    try {
      lastVisit = new Date(base.last_visit_date);
      lastVisit.setHours(0,0,0,0);
    } catch { lastVisit = null; }

    if (lastVisit) {
      const daysSinceVisit = Math.round((now - lastVisit) / (1000 * 60 * 60 * 24));
      if (daysSinceVisit >= 14 && base.churn_email_sent !== 'Yes') {
        actions.push({ json: { ...base, _action: 'churn_risk', days_inactive: daysSinceVisit } });
      }
    }
  }

  // Low engagement: fewer than 4 classes this month mid-month (day 15+)
  const dayOfMonth = now.getDate();
  if (dayOfMonth >= 15 && base.classes_this_month < 4 && base.status === 'Active' && base.churn_email_sent !== 'Yes') {
    // only add if not already added for churn
    const alreadyAdded = actions.find(a => a.json.email === base.email && a.json._action === 'churn_risk');
    if (!alreadyAdded) {
      actions.push({ json: { ...base, _action: 'low_engagement' } });
    }
  }
}

console.log(`Fitness actions: ${actions.length}`);
return actions.length > 0 ? actions : [{ json: { _action: 'none' } }];
